class Solution:
    def lengthOfLIS(self, nums, k):
        n = len(nums)
        dp = [1] * n
        best = 1
        for i in range(n):
            for j in range(i):
                if nums[j] < nums[i] and nums[i] - nums[j] <= k:
                    if dp[j] + 1 > dp[i]:
                        dp[i] = dp[j] + 1
            if dp[i] > best:
                best = dp[i]
        return best

