class Solution:
    def lengthOfLIS(self, nums, k):
        m = max(nums)
        size = m + 1
        tree = [0] * (2 * size)
        def update(pos, val):
            i = pos + size
            if tree[i] >= val:
                return
            tree[i] = val
            i //= 2
            while i >= 1:
                nv = max(tree[2 * i], tree[2 * i + 1])
                if tree[i] == nv:
                    break
                tree[i] = nv
                i //= 2
        def query(lo, hi):
            if lo > hi:
                return 0
            res = 0
            lo += size
            hi += size + 1
            while lo < hi:
                if lo & 1:
                    res = max(res, tree[lo]); lo += 1
                if hi & 1:
                    hi -= 1; res = max(res, tree[hi])
                lo //= 2; hi //= 2
            return res
        best = 0
        for x in nums:
            lo = max(1, x - k)
            best_prev = query(lo, x - 1)
            cur = best_prev + 1
            update(x, cur)
            if cur > best:
                best = cur
        return best

