var lengthOfLIS = function(nums, k) {
    const m = Math.max(...nums);
    const size = m + 1;
    const tree = new Array(2 * size).fill(0);
    const update = (pos, val) => {
        let i = pos + size;
        if (tree[i] >= val) return;
        tree[i] = val;
        i = Math.floor(i / 2);
        while (i >= 1) {
            const nv = Math.max(tree[2 * i], tree[2 * i + 1]);
            if (tree[i] === nv) break;
            tree[i] = nv;
            i = Math.floor(i / 2);
        }
    };
    const query = (lo, hi) => {
        if (lo > hi) return 0;
        let res = 0;
        lo += size;
        hi += size + 1;
        while (lo < hi) {
            if (lo & 1) { res = Math.max(res, tree[lo]); lo++; }
            if (hi & 1) { hi--; res = Math.max(res, tree[hi]); }
            lo = Math.floor(lo / 2); hi = Math.floor(hi / 2);
        }
        return res;
    };
    let best = 0;
    for (const x of nums) {
        const lo = Math.max(1, x - k);
        const cur = query(lo, x - 1) + 1;
        update(x, cur);
        if (cur > best) best = cur;
    }
    return best;
};
